#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');

function runCommand(command, options = {}) {
  console.log(`Executing: ${command}`);
  try {
    execSync(command, { 
      stdio: 'inherit',
      ...options 
    });
  } catch (error) {
    console.error(`Command failed: ${command}`);
    process.exit(1);
  }
}

// Use npm ci for CI/CD (respects package-lock.json exactly)
// Includes --ignore-scripts to prevent automatic postinstall execution
// Then selectively run known scripts if needed
runCommand('npm ci --ignore-scripts');

// Only run specific, vetted scripts if required
if (fs.existsSync('package.json')) {
  const pkg = JSON.parse(fs.readFileSync('package.json', 'utf8'));
  if (pkg.scripts && pkg.scripts.postinstall) {
    console.log('Running package postinstall script...');
    runCommand('npm run postinstall');
  }
}

console.log('Dependencies installed successfully with security checks');